import heapq

def solve(grid: list[list[int]], k: int) -> int:
    m = len(grid)
    n = len(grid[0]) if m > 0 else 0

    # Directions: right (0, 1), down (1, 0)
    dirs = [(0, 1), (1, 0)]

    # Priority queue: (total_cost, i, j, remaining_k)
    heap = []
    heapq.heappush(heap, (0, 0, 0, k))

    # Distance matrix: dist[i][j][k] = min cost to reach (i,j) with k teleports left
    dist = [[[float('inf')] * (k + 1) for _ in range(n)] for __ in range(m)]
    dist[0][0][k] = 0

    while heap:
        cost, i, j, rem_k = heapq.heappop(heap)

        if i == m - 1 and j == n - 1:
            return cost

        if cost > dist[i][j][rem_k]:
            continue

        # Normal moves (right and down)
        for di, dj in dirs:
            ni, nj = i + di, j + dj
            if 0 <= ni < m and 0 <= nj < n:
                new_cost = cost + grid[ni][nj]
                if new_cost < dist[ni][nj][rem_k]:
                    dist[ni][nj][rem_k] = new_cost
                    heapq.heappush(heap, (new_cost, ni, nj, rem_k))

        # Teleport move
        if rem_k > 0:
            for ni in range(m):
