    heap = []
    heapq.heappush(heap, (0, 0, 0, k))

    # Distance matrix: dist[i][j][k] = min cost to reach (i,j) with k teleports left
    dist = [[[float('inf')] * (k + 1) for _ in range(n)] for __ in range(m)]
    dist[0][0][k] = 0

    while heap:
        cost, i, j, rem_k = heapq.heappop(heap)

        if i == m - 1 and j == n - 1:
            return cost

        if cost > dist[i][j][rem_k]:
            continue

        # Normal moves (right and down)
        for di, dj in dirs:
